const body = $json.body ?? $json;
const trim = (value) => String(value ?? '').trim();
const normalizePhone = (value) => {
  const raw = trim(value);
  const digits = raw.replace(/\D+/g, '');
  if (!digits) return '';
  return raw.startsWith('+') ? `+${digits}` : digits;
};
const name = trim(body.name);
const phone = normalizePhone(body.phone);
const email = trim(body.email);
const company = trim(body.company);
const industry = trim(body.industry);
const currentProcess = trim(body.currentProcess);
const desiredOutcome = trim(body.desiredOutcome);
const notes = trim(body.notes ?? body.additionalNotes ?? body.message);
const formType = trim(body.formType ?? 'request_ai_demo');
const leadId = trim(body.lead_id ?? body.leadId) || `lead_${new Date().toISOString().replace(/[-:.TZ]/g, '')}_${Math.random().toString(36).slice(2, 8)}`;
const createdAt = new Date().toISOString();
const delaySeconds = Math.floor(30 + Math.random() * 61);
const errors = [];
if (!name) errors.push('name is required');
if (formType !== 'support' && !phone) errors.push('phone is required');
if (phone && phone.replace(/\D/g, '').length < 8) errors.push('phone must contain at least 8 digits');
if (email && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) errors.push('email is invalid');
return [{ json: { ...body, name, phone, email, company, industry, currentProcess, desiredOutcome, notes, formType, leadId, createdAt, delaySeconds, isValid: errors.length === 0, validationErrors: errors, status: errors.length === 0 ? 'NEW' : 'INVALID', callStatus: errors.length === 0 ? (formType === 'support' ? 'NOT_REQUIRED' : 'PENDING') : 'NOT_STARTED', booked: false, leadScore: 0, advisor: formType === 'support' ? 'Support Team' : '', summary: '', nextAction: errors.length === 0 ? (formType === 'support' ? 'SUPPORT' : 'CALL') : 'RECOVER' } }];

const lead = $json;
const message = `Hi ${lead.name}. We tried reaching out from Praxis Ops. No rush. Reply here with a good time and we'll reconnect.`;
return [{ json: { ...lead, whatsappMessage: message } }];

const lead = $json;
const pickup = lead.pickup !== false;
const engagement = String(lead.sentiment ?? lead.engagement ?? '').toLowerCase();
const objections = String(lead.objections ?? '').toLowerCase();
const urgency = String(lead.urgency ?? lead.timeline ?? '').toLowerCase();
const budget = String(lead.budget ?? '').toLowerCase();
const volume = String(lead.lead_size ?? lead.leadVolume ?? '').toLowerCase();
let score = Number(lead.leadScore || 0);
if (pickup) score += 20;
if (/hot|high|urgent|now|asap|soon/.test(urgency)) score += 20;
if (/large|many|high|growing|frequent/.test(volume)) score += 20;
if (/budget|comfortable|approved|ready|yes/.test(budget)) score += 20;
if (/positive|interested|good|engaged|open/.test(engagement)) score += 20;
if (/price|cost|later|not now|maybe/.test(objections)) score -= 10;
score = Math.max(0, Math.min(100, score));
const segment = score >= 80 ? 'HOT' : score >= 50 ? 'WARM' : 'COLD';
const advisor = segment === 'HOT' ? 'Human Advisor' : segment === 'WARM' ? 'Advisor Queue' : 'Nurture Queue';
const nextAction = segment === 'HOT' ? 'BOOK' : 'FOLLOW_UP';
const summary = lead.summary || lead.call_summary || lead.notes || '';
const conversationNotes = [lead.currentProcess, lead.desiredOutcome, lead.notes, lead.objections].filter(Boolean).join(' | ');
return [{ json: { ...lead, pickup, leadScore: score, segment, advisor, nextAction, summary, conversationNotes, booked: segment === 'HOT' } }];

const lead = $json;
const advisorByIndustry = {
  'real estate': 'Human Advisor - Real Estate',
  healthcare: 'Human Advisor - Healthcare',
  education: 'Human Advisor - Education',
  smb: 'Human Advisor - SMB',
};
const industry = String(lead.industry ?? '').toLowerCase();
const advisor = advisorByIndustry[industry] || lead.advisor || 'Human Advisor';
return [{ json: { ...lead, advisor, booked: true, nextAction: 'CONFIRM_BOOKING' } }];
